import { useState, useEffect, useRef } from 'react';
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import AgentChatPage from './AgentChatPage'; // Assuming you have this component
import { AI_AGENTS } from '../config/agents'; // Import agents data

// Register GSAP plugins
gsap.registerPlugin(ScrollTrigger);

const DashboardPage = ({ user, onLogout }) => {
  const [selectedAgent, setSelectedAgent] = useState(null);
  const [stats, setStats] = useState({
    operations: "2,847",
    revenue: "$48,291",
    time: "342",
    automations: "12",
    leads: "1,847",
    tickets: "342",
    accuracy: "94.2%",
    uptime: "99.97%",
    activeUsers: "127",
    conversionRate: "28.5%",
    avgResponse: "12s"
  });

  // Refs for GSAP animations
  const statsRef = useRef([]);
  const agentsRef = useRef([]);
  const sectionRef = useRef(null);
  const chartRef = useRef(null);

  useEffect(() => {
    // Fetch real stats from backend if needed
    // For now, using static data

    // GSAP Animations - Stats Cards
    gsap.fromTo(statsRef.current,
      { opacity: 0, y: 50 },
      {
        opacity: 1,
        y: 0,
        duration: 0.8,
        stagger: 0.1,
        ease: "back.out(1)",
        scrollTrigger: {
          trigger: statsRef.current[0],
          start: "top 80%",
          toggleActions: "play none none reverse"
        }
      }
    );

    // Agents Cards
    gsap.fromTo(agentsRef.current,
      { scale: 0.9, opacity: 0 },
      {
        scale: 1,
        opacity: 1,
        duration: 0.6,
        stagger: 0.08,
        ease: "elastic.out(1, 0.5)",
        scrollTrigger: {
          trigger: agentsRef.current[0],
          start: "top 85%",
        }
      }
    );

    // Chart line animation (SVG)
    if (chartRef.current) {
      const path = chartRef.current.querySelector('.revenue-path');
      const length = path.getTotalLength();
      gsap.set(path, { strokeDasharray: length, strokeDashoffset: length });
      gsap.to(path, {
        strokeDashoffset: 0,
        duration: 2,
        ease: "power2.out",
        scrollTrigger: {
          trigger: chartRef.current,
          start: "top 80%",
        }
      });
    }
  }, []);

  if (selectedAgent) {
    return <AgentChatPage agent={selectedAgent} onBack={() => setSelectedAgent(null)} />;
  }

  const dashboardStats = [
    { label: "AI Operations Used", value: stats.operations, change: "+23%", icon: "⚡", color: "#A855F7" },
    { label: "Revenue Generated", value: stats.revenue, change: "+12%", icon: "💰", color: "#00D4FF" },
    { label: "Time Saved (hours)", value: stats.time, change: "+156", icon: "⏱️", color: "#10B981" },
    { label: "Active Automations", value: stats.automations, change: "+3", icon: "🔄", color: "#F59E0B" },
    { label: "Leads Processed", value: stats.leads, change: "+23%", icon: "🎯", color: "#6EE7B7" },
    { label: "Tickets Resolved", value: stats.tickets, change: "94% Auto", icon: "✅", color: "#818CF8" },
    { label: "AI Accuracy Rate", value: stats.accuracy, change: "+2.1%", icon: "📊", color: "#38BDF8" },
    { label: "Platform Uptime", value: stats.uptime, change: "99.99%", icon: "🌍", color: "#F472B6" },
    { label: "Active Users", value: stats.activeUsers, change: "+12%", icon: "👥", color: "#A855F7" },
    { label: "Conversion Rate", value: stats.conversionRate, change: "+5.2%", icon: "📈", color: "#10B981" },
    { label: "Avg Response Time", value: stats.avgResponse, change: "-2s", icon: "⚡", color: "#00D4FF" }
  ];

  const recentActivities = [
    { agent: "Sales Agent", action: "Qualified 24 new leads from LinkedIn campaign and scheduled 8 discovery calls", time: "2 min ago", icon: "💼", color: "#6EE7B7" },
    { agent: "Support Agent", action: "Resolved 18 customer tickets automatically with 94% satisfaction rate", time: "15 min ago", icon: "🎧", color: "#818CF8" },
    { agent: "Marketing Agent", action: "Launched new email campaign reaching 12,400 subscribers with 34% open rate", time: "1 hour ago", icon: "📣", color: "#FB923C" },
    { agent: "ChatBot Agent", action: "Handled 47 customer conversations across Instagram, Facebook and WhatsApp", time: "2 hours ago", icon: "💬", color: "#E1306C" },
    { agent: "Analytics Agent", action: "Generated weekly revenue report showing 23% month-over-month growth", time: "3 hours ago", icon: "📊", color: "#38BDF8" },
    { agent: "Finance Agent", action: "Processed 12 invoices and reconciled 34 transactions with zero errors", time: "5 hours ago", icon: "💰", color: "#A3E635" },
    { agent: "Operations Agent", action: "Optimized 3 workflow processes reducing manual work by 67%", time: "6 hours ago", icon: "⚙️", color: "#F472B6" }
  ];

  const performanceMetrics = [
    { label: "Revenue Growth", value: "23%", target: "80%", color: "#10B981" },
    { label: "Customer Satisfaction", value: "98%", target: "95%", color: "#00D4FF" },
    { label: "AI Forecast Accuracy", value: "94.2%", target: "90%", color: "#A855F7" },
    { label: "Cost Reduction", value: "48.2K", target: "45K", color: "#F59E0B" },
    { label: "Lead Conversion", value: "28.5%", target: "25%", color: "#6EE7B7" },
    { label: "Response Time", value: "12s", target: "30s", color: "#818CF8" }
  ];

  const [isDark, setIsDark] = useState(true);
  useEffect(() => {
    const savedTheme = localStorage.getItem('nexusai_theme');
    setIsDark(savedTheme !== 'light');
  }, []);

  return (
    <div className="dashboard-container" style={{
      fontFamily: "'Syne', 'Space Grotesk', sans-serif",
      background: isDark ? "#050508" : "#f5f5f5",
      color: isDark ? "#fff" : "#1a1a1a",
      minHeight: "100vh",
      position: "relative",
      overflowX: "hidden"
    }}>
      
      {/* Animated Background Orbs */}
      <div style={{
        position: "fixed",
        top: "10%",
        left: "-10%",
        width: "500px",
        height: "500px",
        borderRadius: "50%",
        background: "radial-gradient(circle, rgba(168,85,247,0.12), transparent)",
        filter: "blur(80px)",
        animation: "floatOrb 18s ease-in-out infinite",
        pointerEvents: "none",
        zIndex: 0
      }} />
      <div style={{
        position: "fixed",
        bottom: "10%",
        right: "-10%",
        width: "400px",
        height: "400px",
        borderRadius: "50%",
        background: "radial-gradient(circle, rgba(0,212,255,0.08), transparent)",
        filter: "blur(60px)",
        animation: "floatOrb 14s ease-in-out infinite reverse",
        pointerEvents: "none",
        zIndex: 0
      }} />

      {/* Navbar - Same as Homepage */}
      <nav style={{
        position: "sticky",
        top: 0,
        zIndex: 100,
        padding: "16px 40px",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        borderBottom: isDark ? "1px solid rgba(255,255,255,0.05)" : "1px solid rgba(0,0,0,0.08)",
        background: isDark ? "rgba(5,5,8,0.95)" : "rgba(255,255,255,0.95)",
        backdropFilter: "blur(20px)"
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{
            width: 32, height: 32, borderRadius: 8,
            background: "linear-gradient(135deg,#A855F7,#7C3AED)",
            display: "flex", alignItems: "center", justifyContent: "center", fontSize: 16
          }}>⚡</div>
          <span style={{ fontSize: 18, fontWeight: 800, letterSpacing: -0.5 }}>NexusAI Dashboard</span>
        </div>
        <div style={{ display: "flex", gap: 12 }}>
          <button
            onClick={onLogout}
            className="btn-ghost"
            style={{ padding: "9px 20px", borderRadius: 10, fontSize: 14, cursor: "pointer" }}
          >Sign Out</button>
        </div>
      </nav>

      {/* Main Content */}
      <div style={{ padding: "40px", maxWidth: "1400px", margin: "0 auto", position: "relative", zIndex: 2 }}>

        {/* Welcome Section with Animated Gradient */}
        <div className="welcome-section" ref={sectionRef} style={{
          marginBottom: "48px",
          padding: "32px 40px",
          background: isDark ? "rgba(13,13,20,0.6)" : "rgba(255,255,255,0.6)",
          backdropFilter: "blur(12px)",
          borderRadius: "28px",
          border: `1px solid ${isDark ? "rgba(168,85,247,0.2)" : "rgba(168,85,247,0.15)"}`,
          position: "relative",
          overflow: "hidden"
        }}>
          <div style={{
            position: "absolute",
            top: 0, left: 0, right: 0, height: "3px",
            background: "linear-gradient(90deg, #A855F7, #00D4FF, #A855F7)",
            backgroundSize: "200% 100%",
            animation: "gradientFlow 3s linear infinite"
          }} />
          <h1 style={{
            fontSize: "clamp(28px, 4vw, 38px)",
            fontWeight: 800,
            marginBottom: "8px",
            background: "linear-gradient(135deg, #fff, #A855F7)",
            WebkitBackgroundClip: "text",
            WebkitTextFillColor: "transparent"
          }}>Welcome back, {user.name}!</h1>
          <p style={{ color: isDark ? "rgba(255,255,255,0.6)" : "rgba(0,0,0,0.6)" }}>
            Your AI workforce is operating at peak performance. All systems green.
          </p>
        </div>

        {/* Stats Grid - Premium Cards with Hover Animation */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: "20px", marginBottom: "48px" }}>
          {dashboardStats.map((stat, idx) => (
            <div
              key={idx}
              ref={el => statsRef.current[idx] = el}
              className="stat-card-premium"
              style={{
                background: isDark ? "rgba(13,13,20,0.7)" : "rgba(255,255,255,0.7)",
                backdropFilter: "blur(8px)",
                borderRadius: "20px",
                padding: "24px",
                border: `1px solid ${stat.color}30`,
                transition: "all 0.3s cubic-bezier(0.2, 0.9, 0.4, 1.1)",
                cursor: "pointer"
              }}
              onMouseEnter={e => {
                gsap.to(e.currentTarget, { scale: 1.02, duration: 0.2, ease: "power2.out", boxShadow: `0 10px 30px ${stat.color}20` });
              }}
              onMouseLeave={e => {
                gsap.to(e.currentTarget, { scale: 1, duration: 0.2, boxShadow: "none" });
              }}
            >
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "16px" }}>
                <span style={{ fontSize: "13px", letterSpacing: "0.5px", color: isDark ? "rgba(255,255,255,0.5)" : "rgba(0,0,0,0.5)" }}>{stat.label}</span>
                <span style={{ fontSize: "28px" }}>{stat.icon}</span>
              </div>
              <div style={{ fontSize: "34px", fontWeight: 800, color: stat.color, marginBottom: "8px" }}>{stat.value}</div>
              <div style={{ fontSize: "12px", color: "#10B981" }}>{stat.change}</div>
            </div>
          ))}
        </div>

        {/* Two Column Section: Performance Chart + Recent Activity */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "28px", marginBottom: "48px" }}>
          {/* Revenue Chart with GSAP */}
          <div ref={chartRef} style={{
            background: isDark ? "rgba(13,13,20,0.7)" : "rgba(255,255,255,0.7)",
            backdropFilter: "blur(8px)",
            borderRadius: "24px",
            padding: "28px",
            border: `1px solid ${isDark ? "rgba(168,85,247,0.15)" : "rgba(0,0,0,0.08)"}`
          }}>
            <h3 style={{ fontSize: "18px", fontWeight: 700, marginBottom: "4px" }}>Revenue Forecast</h3>
            <p style={{ fontSize: "13px", color: isDark ? "rgba(255,255,255,0.5)" : "rgba(0,0,0,0.5)", marginBottom: "20px" }}>AI-powered predictive analytics</p>
            <svg width="100%" height="160" viewBox="0 0 500 160">
              <defs>
                <linearGradient id="areaGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="#A855F7" stopOpacity="0.4"/>
                  <stop offset="100%" stopColor="#A855F7" stopOpacity="0"/>
                </linearGradient>
              </defs>
              <path className="revenue-path" d="M0,140 C40,130 80,115 120,105 C160,95 200,85 240,70 C280,55 320,60 360,45 C400,30 440,35 480,20 C490,15 495,18 500,10" fill="none" stroke="#A855F7" strokeWidth="3" strokeLinecap="round"/>
              <path d="M0,140 C40,130 80,115 120,105 C160,95 200,85 240,70 C280,55 320,60 360,45 C400,30 440,35 480,20 C490,15 495,18 500,10 L500,160 L0,160 Z" fill="url(#areaGrad)"/>
            </svg>
            <div style={{ display: "flex", justifyContent: "space-between", marginTop: "20px" }}>
              <div><span style={{ fontSize: "24px", fontWeight: 700, color: "#A855F7" }}>$284K</span><div style={{ fontSize: "11px" }}>This Month</div></div>
              <div><span style={{ fontSize: "24px", fontWeight: 700 }}>+23%</span><div style={{ fontSize: "11px" }}>MoM Growth</div></div>
              <div><span style={{ fontSize: "24px", fontWeight: 700, color: "#00D4FF" }}>94.2%</span><div style={{ fontSize: "11px" }}>Accuracy</div></div>
            </div>
          </div>

          {/* Recent Activity Feed */}
          <div style={{
            background: isDark ? "rgba(13,13,20,0.7)" : "rgba(255,255,255,0.7)",
            backdropFilter: "blur(8px)",
            borderRadius: "24px",
            padding: "28px",
            border: `1px solid ${isDark ? "rgba(168,85,247,0.15)" : "rgba(0,0,0,0.08)"}`
          }}>
            <h3 style={{ fontSize: "18px", fontWeight: 700, marginBottom: "20px" }}>Real-time Agent Activity</h3>
            <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
              {recentActivities.slice(0, 5).map((act, idx) => (
                <div key={idx} className="activity-item" style={{
                  display: "flex", alignItems: "center", gap: "14px",
                  padding: "10px 0", borderBottom: idx < 4 ? `1px solid ${isDark ? "rgba(255,255,255,0.05)" : "rgba(0,0,0,0.05)"}` : "none",
                  transition: "transform 0.2s"
                }}>
                  <div style={{ width: "44px", height: "44px", borderRadius: "12px", background: `${act.color}15`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: "22px" }}>{act.icon}</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 600, fontSize: "14px" }}>{act.agent}</div>
                    <div style={{ fontSize: "12px", color: isDark ? "rgba(255,255,255,0.5)" : "rgba(0,0,0,0.5)" }}>{act.action}</div>
                  </div>
                  <div style={{ fontSize: "11px", color: isDark ? "rgba(255,255,255,0.3)" : "rgba(0,0,0,0.3)" }}>{act.time}</div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Performance Metrics with Progress Bars */}
        <div style={{
          background: isDark ? "rgba(13,13,20,0.7)" : "rgba(255,255,255,0.7)",
          backdropFilter: "blur(8px)",
          borderRadius: "24px",
          padding: "28px",
          border: `1px solid ${isDark ? "rgba(168,85,247,0.15)" : "rgba(0,0,0,0.08)"}`,
          marginBottom: "48px"
        }}>
          <h3 style={{ fontSize: "18px", fontWeight: 700, marginBottom: "24px" }}>Key Performance Indicators</h3>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))", gap: "20px" }}>
            {performanceMetrics.map((metric, idx) => (
              <div key={idx}>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "8px" }}>
                  <span style={{ fontSize: "13px", color: isDark ? "rgba(255,255,255,0.7)" : "rgba(0,0,0,0.7)" }}>{metric.label}</span>
                  <span style={{ fontSize: "13px", fontWeight: 600, color: metric.color }}>{metric.value}</span>
                </div>
                <div style={{ height: "6px", background: isDark ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.08)", borderRadius: "10px", overflow: "hidden" }}>
                  <div style={{ width: `${parseInt(metric.value)}%`, height: "100%", background: `linear-gradient(90deg, ${metric.color}, ${metric.color}80)`, borderRadius: "10px" }} />
                </div>
                <div style={{ fontSize: "11px", marginTop: "6px", color: isDark ? "rgba(255,255,255,0.4)" : "rgba(0,0,0,0.4)" }}>Target: {metric.target}</div>
              </div>
            ))}
          </div>
        </div>

        {/* AI Agents Grid - Premium Cards with Hover Reveal */}
        <div style={{ marginBottom: "48px" }}>
          <h2 style={{ fontSize: "28px", fontWeight: 800, letterSpacing: "-1px", marginBottom: "28px" }}>Your AI Agents</h2>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))", gap: "24px" }}>
            {AI_AGENTS.map((agent, idx) => (
              <div
                key={agent.id}
                ref={el => agentsRef.current[idx] = el}
                onClick={() => setSelectedAgent(agent)}
                className="agent-card-premium"
                style={{
                  background: isDark ? `linear-gradient(135deg, ${agent.color}10, #0d0d14)` : `linear-gradient(135deg, ${agent.color}08, #ffffff)`,
                  border: `1px solid ${agent.color}30`,
                  borderRadius: "24px",
                  padding: "28px",
                  textAlign: "center",
                  cursor: "pointer",
                  position: "relative",
                  overflow: "hidden",
                  transition: "all 0.3s"
                }}
              >
                <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: "4px", background: `linear-gradient(90deg, ${agent.color}, #A855F7)`, transform: "scaleX(0)", transition: "transform 0.3s", transformOrigin: "left" }} className="agent-card-hover-line" />
                <div style={{ fontSize: "52px", marginBottom: "16px" }}>{agent.icon}</div>
                <h3 style={{ fontSize: "20px", fontWeight: 700, marginBottom: "8px", background: `linear-gradient(135deg, #fff, ${agent.color})`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>{agent.name}</h3>
                <p style={{ fontSize: "12px", color: agent.color, marginBottom: "16px" }}>{agent.tagline}</p>
                <div style={{ display: "inline-block", background: `${agent.color}15`, padding: "6px 16px", borderRadius: "40px", fontSize: "11px", fontWeight: 600, color: agent.color }}>Active</div>
              </div>
            ))}
          </div>
        </div>

        {/* Additional Analytics Section */}
        <div style={{
          background: isDark ? "rgba(13,13,20,0.7)" : "rgba(255,255,255,0.7)",
          backdropFilter: "blur(8px)",
          borderRadius: "24px",
          padding: "28px",
          border: `1px solid ${isDark ? "rgba(168,85,247,0.15)" : "rgba(0,0,0,0.08)"}`,
          marginBottom: "48px"
        }}>
          <h3 style={{ fontSize: "18px", fontWeight: 700, marginBottom: "20px" }}>AI Efficiency Insights</h3>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "20px", textAlign: "center" }}>
            <div><div style={{ fontSize: "32px", fontWeight: 800, color: "#00D4FF" }}>87%</div><div style={{ fontSize: "12px" }}>Ticket Auto-resolution</div></div>
            <div><div style={{ fontSize: "32px", fontWeight: 800, color: "#6EE7B7" }}>3.4x</div><div style={{ fontSize: "12px" }}>Revenue Increase</div></div>
            <div><div style={{ fontSize: "32px", fontWeight: 800, color: "#A855F7" }}>94%</div><div style={{ fontSize: "12px" }}>Forecast Accuracy</div></div>
          </div>
        </div>
      </div>

      {/* Footer - Same as Homepage */}
      <footer style={{
        borderTop: `1px solid ${isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.08)"}`,
        padding: "40px",
        textAlign: "center",
        color: isDark ? "rgba(255,255,255,0.4)" : "rgba(0,0,0,0.4)",
        fontSize: "13px",
        fontFamily: "'DM Sans', sans-serif"
      }}>
        <p>© 2026 NexusAI Inc. All rights reserved. Serving 137 countries worldwide with 99.99% platform uptime.</p>
        <div style={{ display: "flex", justifyContent: "center", gap: "28px", marginTop: "16px" }}>
          {["Privacy Policy", "Terms of Service", "Security", "Status", "Documentation"].map(link => (
            <span key={link} style={{ cursor: "pointer" }}>{link}</span>
          ))}
        </div>
      </footer>

      <style>{`
        @keyframes floatOrb {
          0%, 100% { transform: translateY(0px) translateX(0px); }
          50% { transform: translateY(-40px) translateX(30px); }
        }
        @keyframes gradientFlow {
          0% { background-position: 0% 50%; }
          100% { background-position: 200% 50%; }
        }
        .stat-card-premium {
          transition: all 0.3s;
        }
        .stat-card-premium:hover {
          transform: translateY(-6px);
        }
        .agent-card-premium:hover .agent-card-hover-line {
          transform: scaleX(1);
        }
        .agent-card-premium {
          transition: transform 0.3s, box-shadow 0.3s;
        }
        .agent-card-premium:hover {
          transform: translateY(-8px);
          box-shadow: 0 20px 40px rgba(0,0,0,0.2);
        }
        .activity-item:hover {
          transform: translateX(6px);
        }
        @media (max-width: 768px) {
          .dashboard-container > div {
            padding-left: 20px !important;
            padding-right: 20px !important;
          }
          .dashboard-stats {
            grid-template-columns: repeat(2, 1fr) !important;
          }
          .agents-grid {
            grid-template-columns: repeat(2, 1fr) !important;
          }
          .two-column {
            grid-template-columns: 1fr !important;
          }
          nav {
            padding: 12px 20px !important;
          }
        }
        @media (max-width: 480px) {
          .dashboard-stats {
            grid-template-columns: 1fr !important;
          }
          .agents-grid {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </div>
  );
};

export default DashboardPage;
